sql:
SELECT course_id, session_id, meeting_days, meeting_time
FROM course_sessions
WHERE course_session_id = 1;

SELECT course_id, personnel_id, role_id, is_primary
FROM course_personnel
WHERE is_primary = 1;

external_knowledge:
- 'Summer courses' refers to courses offered during the summer session;
- 'Maryland' is implied by the affiliation location containing 'MD', which is commonly known as the abbreviation for the state of Maryland;
- 'Staff' refers to personnel with the roles of either 'Course Director' or 'Lecturer'.
